   546→function drawGlueNineSliceToCanvas(
   547→  canvas: HTMLCanvasElement,
   548→  bgImg: HTMLImageElement,
   549→  borderImg: HTMLImageElement,
   550→  hoverImg: HTMLImageElement | null,
   551→  hovered: boolean,
   552→) {
   553→  const cssW = Math.max(1, canvas.clientWidth || 1);
   554→  const cssH = Math.max(1, canvas.clientHeight || 1);
   555→  const dpr = window.devicePixelRatio || 1;
   556→  const pxW = Math.max(1, Math.round(cssW * dpr));
   557→  const pxH = Math.max(1, Math.round(cssH * dpr));
   558→  if (canvas.width !== pxW || canvas.height !== pxH) {
   559→    canvas.width = pxW;
   560→    canvas.height = pxH;
   561→  }
   562→
   563→  const ctx = canvas.getContext('2d');
   564→  if (!ctx) return;
   565→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
   566→  ctx.clearRect(0, 0, cssW, cssH);
   567→
   568→  const atlasW = borderImg.width;
   569→  const atlasH = borderImg.height;
   570→  const cellW = atlasW / 8;
   571→  const corner = Math.max(1, Math.floor(Math.min(cellW, cssH * 0.35, cssW / 2, cssH / 2)));
   572→  const inset = Math.max(1, Math.round(corner * 0.25));
   573→
   574→  // Fill inner area with opaque black before pattern to handle textures with alpha
   575→  // (NightElf/Undead bg textures use DXT3/5 with alpha; game renders on opaque framebuffer)
   576→  ctx.fillStyle = '#000';
   577→  ctx.fillRect(inset, inset, cssW - inset * 2, cssH - inset * 2);
   578→
   579→  const pattern = ctx.createPattern(bgImg, 'repeat');
   580→  if (pattern) {
   581→    ctx.fillStyle = pattern;
   582→    ctx.fillRect(inset, inset, cssW - inset * 2, cssH - inset * 2);
   583→  }
   584→
   585→  const drawCell = (idx: number, x: number, y: number, w: number, h: number) => {
   586→    ctx.drawImage(borderImg, idx * cellW, 0, cellW, atlasH, x, y, w, h);
   587→  };
   588→
   589→  drawCell(4, 0, 0, corner, corner);
   590→  drawCell(5, cssW - corner, 0, corner, corner);
   591→  drawCell(6, 0, cssH - corner, corner, corner);
   592→  drawCell(7, cssW - corner, cssH - corner, corner, corner);
   593→
   594→  const edgeH = cssH - corner * 2;
   595→  if (edgeH > 0) {
   596→    drawCell(0, 0, corner, corner, edgeH);
   597→    drawCell(1, cssW - corner, corner, corner, edgeH);
   598→  }
   599→
   600→  const edgeW = cssW - corner * 2;
   601→  if (edgeW > 0) {
   602→    const topRot = rotateCellClockwise(borderImg, 2, cellW, atlasH);
   603→    const bottomRot = rotateCellClockwise(borderImg, 3, cellW, atlasH);
   604→    ctx.drawImage(topRot, corner, 0, edgeW, corner);
   605→    ctx.drawImage(bottomRot, corner, cssH - corner, edgeW, corner);
   606→  }
