   635→function drawHorizontallyTiledEdge(
   636→  ctx: CanvasRenderingContext2D,
   637→  tile: HTMLCanvasElement,
   638→  x: number,
   639→  y: number,
   640→  width: number,
   641→  height: number,
   642→) {
   643→  if (width <= 0 || height <= 0) return;
   644→
   645→  let drawn = 0;
   646→  while (drawn < width) {
   647→    const segmentW = Math.min(height, width - drawn);
   648→    const srcW = (segmentW / height) * tile.width;
   649→    ctx.drawImage(tile, 0, 0, srcW, tile.height, x + drawn, y, segmentW, height);
   650→    drawn += segmentW;
   651→  }
   652→}
