   700→    if (options.opaqueBaseFill) {
   701→      ctx.fillStyle = options.opaqueBaseFill;
   702→      ctx.fillRect(innerX, innerY, innerW, innerH);
   703→    }
   704→    if (options.tileBackground === false) {
   705→      ctx.drawImage(bgImg, 0, 0, bgImg.width, bgImg.height, innerX, innerY, innerW, innerH);
   706→    } else {
   707→      const pattern = ctx.createPattern(bgImg, 'repeat');
   708→      if (pattern) {
   709→        ctx.fillStyle = pattern;
   710→        ctx.fillRect(innerX, innerY, innerW, innerH);
   711→      }
   712→    }
   713→    ctx.restore();
   714→  }
   715→
   716→  const drawCell = (idx: number, x: number, y: number, w: number, h: number) => {
   717→    ctx.drawImage(borderImg, idx * cellW, 0, cellW, atlasH, x, y, w, h);
   718→  };
   719→
   720→  drawCell(4, 0, 0, corner, corner);
   721→  drawCell(5, cssW - corner, 0, corner, corner);
   722→  drawCell(6, 0, cssH - corner, corner, corner);
   723→  drawCell(7, cssW - corner, cssH - corner, corner, corner);
   724→
   725→  const edgeH = cssH - corner * 2;
   726→  if (edgeH > 0) {
   727→    drawCell(0, 0, corner, corner, edgeH);
   728→    drawCell(1, cssW - corner, corner, corner, edgeH);
   729→  }
   730→
   731→  const edgeW = cssW - corner * 2;
   732→  if (edgeW > 0) {
   733→    const topRot = rotateCellClockwise(borderImg, 2, cellW, atlasH);
   734→    const bottomRot = rotateCellClockwise(borderImg, 3, cellW, atlasH);
   735→    if (options.tileHorizontalEdges) {
   736→      drawHorizontallyTiledEdge(ctx, topRot, corner, 0, edgeW, corner);
   737→      drawHorizontallyTiledEdge(ctx, bottomRot, corner, cssH - corner, edgeW, corner);
   738→    } else {
   739→      ctx.drawImage(topRot, corner, 0, edgeW, corner);
   740→      ctx.drawImage(bottomRot, corner, cssH - corner, edgeW, corner);
   741→    }
   742→  }
