   745→function composeBorderImageFromAtlas(atlas: HTMLImageElement): string {
   746→  const cellW = atlas.width / 8;
   747→  const cellH = atlas.height;
   748→  const cell = Math.max(1, Math.floor(Math.min(cellW, cellH)));
   749→  const canvas = document.createElement('canvas');
   750→  canvas.width = cell * 3;
   751→  canvas.height = cell * 3;
   752→  const ctx = canvas.getContext('2d');
   753→  if (!ctx) return '';
   754→  ctx.clearRect(0, 0, canvas.width, canvas.height);
   755→  ctx.imageSmoothingEnabled = false;
   756→
