   776→function modelBarFillRatio(valuePct: number, profile: StatusBarFillProfile): number {
   777→  const pct = Math.max(0, Math.min(100, valuePct));
   778→  const scaleX = profile.minScaleX + ((profile.maxScaleX - profile.minScaleX) * pct) / 100;
