   900→function interpolateKeyframes(ms: number, keyframes: ReadonlyArray<readonly [number, number]>): number {
   901→  if (keyframes.length === 0) return 0;
   902→  if (ms <= keyframes[0][0]) return keyframes[0][1];
   903→  for (let i = 1; i < keyframes.length; i++) {
   904→    const [frameMs, frameVal] = keyframes[i];
   905→    const [prevMs, prevVal] = keyframes[i - 1];
   906→    if (ms <= frameMs) {
   907→      const t = (ms - prevMs) / Math.max(0.0001, frameMs - prevMs);
   908→      return prevVal + (frameVal - prevVal) * t;
   909→    }
   910→  }
   911→  return keyframes[keyframes.length - 1][1];
   912→}
