   931→function loadingProgressPct(ms: number): number {
   932→  const cycleMs = progressAnimCycleMs;
   933→  const wrappedMs = ((ms % cycleMs) + cycleMs) % cycleMs;
   934→  const finalMs = cycleMs - loadingSmoothToStutterMs - loadingStutterDurationMs;
   935→
   936→  if (wrappedMs < loadingSmoothToStutterMs) {
   937→    const t = wrappedMs / loadingSmoothToStutterMs;
   938→    return easeOutCubic(t) * loadingStutterStartPct;
   939→  }
   940→
   941→  if (wrappedMs < loadingSmoothToStutterMs + loadingStutterDurationMs) {
   942→    return loadingStutterPct(wrappedMs - loadingSmoothToStutterMs);
   943→  }
   944→
   945→  const finalT = (wrappedMs - loadingSmoothToStutterMs - loadingStutterDurationMs) / Math.max(1, finalMs);
   946→  return loadingStutterEndPct + easeOutCubic(finalT) * (100 - loadingStutterEndPct);
